            ctx.save();
            ctx.beginPath();
            ctx.arc(circle.x, circle.y, circle.r, 0, Math.PI * 2, false);
            ctx.clip();
            ctx.drawImage(img, 0, 0, dw, dh);
            ctx.restore();
